export default VitalSignsAlert;

import { useEffect } from "react";
import { VitalSignsFhirProps } from "../types/vital-signs";
import { FhirBundle } from "../types/vital-signs";
import {FhirBundleEntry} from "../types/vital-signs" 

const VitalSignsFhir = ({
  bloodPressureValue,
  heartRateValue,
  respiratoryRateValue,
  temperatureValue,
  bloodOxygenValue,
  fio2Value,
  onFhirUpdate,
  useFahrenheit = true,
  patientId = "Patient/example",
}: VitalSignsFhirProps) => {
  const generateId = (type: string): string => {
    const timestamp = Date.now();
    const random = Math.floor(Math.random() * 1000);
    return `${type}-${timestamp}-${random}`;
  };

  const getCurrentTimestamp = (): string => {
    return new Date().toISOString();
  };

  const convertToFhir = (): FhirBundle => {
    const entries: FhirBundleEntry[] = [];
    const currentTime = getCurrentTimestamp();

    if (
      bloodPressureValue &&
      bloodPressureValue?.systolic !== null &&
      bloodPressureValue?.diastolic !== null
    ) {
      entries.push({
        resource: {
          resourceType: "Observation",
          id: generateId("bp"),
          subject: { reference: patientId },
          effectiveDateTime: currentTime,
          code: {
            coding: [
              {
                system: "http://loinc.org",
                code: "85354-9",
                display: "Blood pressure panel with all children optional",
              },
            ],
            text: "Blood Pressure",
          },
          component: [
            {
              code: {
                coding: [
                  {
                    system: "http://loinc.org",
                    code: "8480-6",
                    display: "Systolic blood pressure",
                  },
                ],
              },
              valueQuantity: {
                value: bloodPressureValue.systolic!,
                unit: "mmHg",
                system: "http://unitsofmeasure.org",
                code: "mm[Hg]",
              },
            },
            {
              code: {
                coding: [
                  {
                    system: "http://loinc.org",
                    code: "8462-4",
                    display: "Diastolic blood pressure",
                  },
                ],
              },
              valueQuantity: {
                value: bloodPressureValue.diastolic!,
                unit: "mmHg",
                system: "http://unitsofmeasure.org",
                code: "mm[Hg]",
              },
            },
          ],
          status: "final",
        },
      });
    }

    // Heart Rate
    if (heartRateValue !== null && heartRateValue !== undefined) {
      entries.push({
        resource: {
          resourceType: "Observation",
          id: generateId("hr"),
          subject: { reference: patientId },
          effectiveDateTime: currentTime,
          code: {
            coding: [
              {
                system: "http://loinc.org",
                code: "8867-4",
                display: "Heart rate",
              },
            ],
          },
          valueQuantity: {
            value: heartRateValue,
            unit: "beats/minute",
            system: "http://unitsofmeasure.org",
            code: "/min",
          },
          status: "final",
        },
      });
    }

    // Respiratory Rate
    if (respiratoryRateValue !== null && respiratoryRateValue !== undefined) {
      entries.push({
        resource: {
          resourceType: "Observation",
          id: generateId("rr"),
          subject: { reference: patientId },
          effectiveDateTime: currentTime,
          code: {
            coding: [
              {
                system: "http://loinc.org",
                code: "9279-1",
                display: "Respiratory rate",
              },
            ],
          },
          valueQuantity: {
            value: respiratoryRateValue,
            unit: "breaths/minute",
            system: "http://unitsofmeasure.org",
            code: "/min",
          },
          status: "final",
        },
      });
    }

    // Temperature
    if (temperatureValue !== null && temperatureValue !== undefined) {
      const tempUnit = useFahrenheit ? "°F" : "°C";
      const tempCode = useFahrenheit ? "°F" : "°C";

      entries.push({
        resource: {
          resourceType: "Observation",
          id: generateId("temp"),
          subject: { reference: patientId },
          effectiveDateTime: currentTime,
          code: {
            coding: [
              {
                system: "http://loinc.org",
                code: "8310-5",
                display: "Body temperature",
              },
            ],
          },
          valueQuantity: {
            value: temperatureValue,
            unit: tempUnit,
            system: "http://unitsofmeasure.org",
            code: tempCode,
          },
          status: "final",
        },
      });
    }

    // Blood Oxygen Saturation
    if (bloodOxygenValue !== null && bloodOxygenValue !== undefined) {
      entries.push({
        resource: {
          resourceType: "Observation",
          id: generateId("spo2"),
          subject: { reference: patientId },
          effectiveDateTime: currentTime,
          code: {
            coding: [
              {
                system: "http://loinc.org",
                code: "59408-5",
                display:
                  "Oxygen saturation in Arterial blood by Pulse oximetry",
              },
            ],
          },
          valueQuantity: {
            value: bloodOxygenValue,
            unit: "%",
            system: "http://unitsofmeasure.org",
            code: "%",
          },
          status: "final",
        },
      });
    }

    // FiO2
    if (fio2Value !== null && fio2Value !== undefined) {
      entries.push({
        resource: {
          resourceType: "Observation",
          id: generateId("fio2"),
          subject: { reference: patientId },
          effectiveDateTime: currentTime,
          code: {
            coding: [
              {
                system: "http://loinc.org",
                code: "3151-8",
                display: "Fraction of inspired oxygen (FiO2)",
              },
            ],
          },
          valueQuantity: {
            value: fio2Value,
            unit: "%",
            system: "http://unitsofmeasure.org",
            code: "%",
          },
          status: "final",
        },
      });
    }

    return {
      resourceType: "Bundle",
      id: generateId("bundle"),
      type: "collection",
      entry: entries,
    };
  };

  useEffect(() => {
    const newFhirBundle = convertToFhir();

    if (onFhirUpdate) {
      onFhirUpdate(newFhirBundle);
    }
  }, [
    bloodPressureValue,
    heartRateValue,
    respiratoryRateValue,
    temperatureValue,
    bloodOxygenValue,
    fio2Value,
    onFhirUpdate,
    useFahrenheit,
    patientId,
  ]);

  return null;
};

export default VitalSignsFhir;

import { useState } from "react";

export const useAnalyzeVitalSigns = ({ route, getCurrentVitalSignsData }) => {
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState("");
  const [analysis, setAnalysis] = useState("");
  const [showAnalysis, setShowAnalysis] = useState(false);

  const analyzeVitalSigns = async () => {
    setIsLoading(true);
    setError("");
    setAnalysis("");
    const vitalSigns = getCurrentVitalSignsData();
    if (!route) return;
    try {
      const response = await fetch(route, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ vitalSigns }),
      });
      const data = await response.json();
      if (!response.ok) {
        throw new Error(data.error || "Failed to analyze vital signs");
      }
      setAnalysis(data.analysis);
      setShowAnalysis(true);
    } catch (err) {
      if (err instanceof Error) {
        setError(err.message);
      } else {
        setError("An unknown error occurred");
      }
    } finally {
      setIsLoading(false);
    }
  };

  const resetAnalysis = () => {
    setShowAnalysis(false);
    setAnalysis("");
    setError("");
  };

  const clearAnalysis = () => {
    setAnalysis("");
    setShowAnalysis(false);
    setIsLoading(false);
  };

  return {
    analyzeVitalSigns,
    resetAnalysis,
    clearAnalysis,
    isLoading,
    error,
    analysis,
    showAnalysis,
  };
};

import { useEffect, useRef } from "react";

export const useClickOutside = (callback: () => void) => {
  const ref = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (ref.current && !ref.current.contains(event.target as Node)) {
        callback();
      }
    };

    document.addEventListener("mousedown", handleClickOutside);
    return () => {
      document.removeEventListener("mousedown", handleClickOutside);
    };
  }, [callback]);

  return ref;
};

// hooks/useVitalSigns.ts
import { useState, useCallback } from "react";
import {
  IVitalSignsData,
  IBloodPressureValue,
  IBloodOxygen,
  FhirBundle,
  BloodPressureValue,
  UseVitalSignsReturn
} from "../types/vital-signs";

export const useVitalSigns = (
  initialData?: Partial<IVitalSignsData>,
): UseVitalSignsReturn => {

  const [heartRate, setHeartRate] = useState<number | null>(
    initialData?.heartRate ?? null,
  );
  const [respiratoryRate, setRespiratoryRate] = useState<number | null>(
    initialData?.respiratoryRate ?? null,
  );
  const [temperature, setTemperature] = useState<number | null>(
    initialData?.temperature ?? null,
  );
  const [bloodOxygen, setBloodOxygen] = useState<IBloodOxygen>(
    initialData?.bloodOxygen ?? { saturation: null, fiO2: 21 },
  );
  const [bloodPressure, setBloodPressure] = useState<IBloodPressureValue>(
    initialData?.bloodPressure ?? { systolic: null, diastolic: null },
  );
  const [fhirBundle, setFhirBundle] = useState<unknown>(
    initialData?.fhirBundle,
  );
  const [timestamp, setTimestamp] = useState<string>(
    initialData?.timestamp ?? new Date().toISOString(),
  );

  const parseNumericValue = useCallback(
    (value: string | number): number | null => {
      if (value === null || value === undefined || value === "") return null;
      const numValue = typeof value === "string" ? parseFloat(value) : value;
      return isNaN(numValue) ? null : numValue;
    },
    [],
  );

  const createNumericHandler = useCallback(
    (setter: (value: number | null) => void) => (value: string | number) => {
      const parsedValue = parseNumericValue(value);
      setter(parsedValue);
      setTimestamp(new Date().toISOString());
    },
    [parseNumericValue],
  );

  const handleHeartRate = createNumericHandler(setHeartRate);
  const handleRespiratoryRate = createNumericHandler(setRespiratoryRate);
  const handleTemperature = createNumericHandler(setTemperature);

  const handleBloodOxygen = useCallback(
    (value: string | number) => {
      const parsedValue = parseNumericValue(value);
      setBloodOxygen((prev) => ({ ...prev, saturation: parsedValue }));
      setTimestamp(new Date().toISOString());
    },
    [parseNumericValue],
  );

  const handleFio2 = useCallback(
    (value: string | number) => {
      const parsedValue = parseNumericValue(value);
      setBloodOxygen((prev) => ({ ...prev, fiO2: parsedValue }));
      setTimestamp(new Date().toISOString());
    },
    [parseNumericValue],
  );

  const handleBloodPressure = useCallback(
    (value: BloodPressureValue) => {
      const convertedValue: IBloodPressureValue = {
        systolic: parseNumericValue(value.systolic ?? ""),
        diastolic: parseNumericValue(value.diastolic ?? ""),
      };
      setBloodPressure(convertedValue);
      setTimestamp(new Date().toISOString());
    },
    [parseNumericValue],
  );

  const handleFhirUpdate = useCallback((bundle: FhirBundle) => {
    setFhirBundle(bundle);
    setTimestamp(new Date().toISOString());
  }, []);

  const resetValues = useCallback(() => {
    setHeartRate(null);
    setRespiratoryRate(null);
    setTemperature(null);
    setBloodOxygen({ saturation: null, fiO2: 21 });
    setBloodPressure({ systolic: null, diastolic: null });
    setFhirBundle(undefined);
    setTimestamp(new Date().toISOString());
  }, []);

  const updateFromData = useCallback((data: Partial<IVitalSignsData>) => {
    if (data.heartRate !== undefined) setHeartRate(data.heartRate);
    if (data.respiratoryRate !== undefined)
      setRespiratoryRate(data.respiratoryRate);
    if (data.temperature !== undefined) setTemperature(data.temperature);
    if (data.bloodOxygen !== undefined) setBloodOxygen(data.bloodOxygen);
    if (data.bloodPressure !== undefined) setBloodPressure(data.bloodPressure);
    if (data.fhirBundle !== undefined) setFhirBundle(data.fhirBundle);
    if (data.timestamp !== undefined) setTimestamp(data.timestamp);
    else setTimestamp(new Date().toISOString());
  }, []);

  const values: IVitalSignsData = {
    heartRate,
    respiratoryRate,
    temperature,
    bloodOxygen,
    bloodPressure,
    fhirBundle,
    timestamp,
  };

  return {
    values,
    handlers: {
      handleHeartRate,
      handleRespiratoryRate,
      handleTemperature,
      handleBloodOxygen,
      handleFio2,
      handleBloodPressure,
      handleFhirUpdate,
      resetValues,
      updateFromData,
    },
  };
};

