/**
 * Type definitions for the VitalSigns component system.
 *
 * Key types for consumers:
 *   IVitalSignsProps  — Props for the main <VitalSigns> component
 *   IVitalSignsData   — Shape of vital signs data (passed via `data` prop and returned in `onData`)
 *   FhirBundle        — FHIR R4 Bundle returned alongside data in `onData` callback
 *
 * Internal types (used by sub-components):
 *   BloodPressureProps, HeartRateProps, RespiratoryRateProps,
 *   TemperatureProps, BloodOxygenProps — individual sign component props
 *   EditSectionProps — reusable edit overlay component props
 *   UseVitalSignsReturn — return type from useVitalSigns hook
 */
import { ReactNode } from "react";

export interface VitalSignsFhirProps {
  bloodPressureValue?: BloodPressureValue;
  heartRateValue?: number | null;
  respiratoryRateValue?: number | null;
  temperatureValue?: number | null;
  bloodOxygenValue?: number | null; 
  fio2Value?: number | null; 
  onFhirUpdate?: (bundle: FhirBundle) => void;
  useFahrenheit?: boolean;
  patientId?: string;
}


export interface IBloodOxygen {
  saturation: number | null;
  fiO2: number | null;
}

export interface IBloodPressureValue {
  systolic: number | null;
  diastolic: number | null;
}
export interface IVitalSignsData {
  bloodPressure: IBloodPressureValue;
  heartRate: number | null;
  respiratoryRate: number | null;
  temperature: number | null;
  bloodOxygen: IBloodOxygen;
  fhirBundle?: unknown;
  timestamp?: string;
}

export interface IVitalSignsProps {
  data?: IVitalSignsData;
  minimizedVertical?: boolean;
  onData?: (data: IVitalSignsData, fhir?: FhirBundle) => void;
  assistant?: boolean;
  useFahrenheit?: boolean;
  editable?: boolean;
  border?: boolean;
  assistantRoute?: string;
}

export interface BloodPressureValue {
  systolic: number | null;
  diastolic: number | null;
}

interface FhirCoding {
  system: string;
  code: string;
  display: string;
}

interface FhirCodeableConcept {
  coding: FhirCoding[];
  text?: string;
}

interface FhirQuantity {
  value: number | string;
  unit: string;
  system: string;
  code: string;
}

interface FhirObservationComponent {
  code: FhirCodeableConcept;
  valueQuantity: FhirQuantity;
}

interface FhirObservation {
  resourceType: "Observation";
  id?: string;
  code: FhirCodeableConcept;
  valueQuantity?: FhirQuantity;
  component?: FhirObservationComponent[];
  status:
    | "final"
    | "preliminary"
    | "registered"
    | "cancelled"
    | "entered-in-error"
    | "unknown";
  subject?: { reference: string }; 
  effectiveDateTime?: string;
}

export interface FhirBundleEntry {
  resource: FhirObservation;
}

export interface FhirBundle {
  resourceType: "Bundle";
  id?: string;
  type:
    | "collection"
    | "document"
    | "message"
    | "transaction"
    | "transaction-response"
    | "batch"
    | "batch-response"
    | "history"
    | "searchset";
  entry: FhirBundleEntry[];
}

export interface UseVitalSignsReturn {
